const amqp = require('amqplib/callback_api');

// Connection details
const connectionDetails = {
  host: 'rabbitmq_host',
  user: 'rabbitmq_username',
  pass: 'rabbitmq_password'
};

const queueName = 'payment_queue';

amqp.connect(connectionDetails).then(function(conn) {
  process.once('SIGINT', function() { conn.close(); });

  return conn.createChannel().then(function(channel) {
    channel.assertQueue(queueName, { durable: false });

    console.log(" [*] Waiting for messages in %s. To exit press CTRL+C", queueName);

    channel.consume(queueName, function(msg) {
      const paymentEvent = JSON.parse(msg.content.toString());

      // Execute the payment logic based on message content
      console.log(" [x] Received payment event:", paymentEvent);

      // Handle the response (optional)
      channel.ack(msg);
    }, { noAck: false });
  });
});